115: type shutdown struct {
116: 	stopCh <-chan struct{}
117: }
118: 
119: // NewShutdownHealthz returns a new HealthChecker that will fail if the embedded channel is closed.
120: // This is intended to allow for graceful shutdown sequences.
121: func NewShutdownHealthz(stopCh <-chan struct{}) HealthChecker {
122: 	return &shutdown{stopCh}
123: }
124: 
125: func (s *shutdown) Name() string {
126: 	return "shutdown"
127: }
128: 
129: func (s *shutdown) Check(req *http.Request) error {
130: 	select {
131: 	case <-s.stopCh:
132: 		return fmt.Errorf("process is shutting down")
133: 	default:
134: 	}
135: 	return nil
136: }
137: 
138: func (i *informerSync) Check(_ *http.Request) error {
139: 	stopCh := make(chan struct{})
140: 	// Close stopCh to force checking if informers are synced now.
141: 	close(stopCh)
142: 
143: 	informersByStarted := make(map[bool][]string)
144: 	for informerType, started := range i.cacheSyncWaiter.WaitForCacheSync(stopCh) {
145: 		informersByStarted[started] = append(informersByStarted[started], informerType.String())
146: 	}
147: 
148: 	if notStarted := informersByStarted[false]; len(notStarted) > 0 {
149: 		return fmt.Errorf("%d informers not started yet: %v", len(notStarted), notStarted)
150: 	}
151: 	return nil
152: }
