191: // InstallPathHandler registers handlers for health checking on
192: // a specific path to mux. *All handlers* for the path must be
193: // specified in exactly one call to InstallPathHandler. Calling
194: // InstallPathHandler more than once for the same path and mux will
195: // result in a panic.
196: func InstallPathHandler(mux mux, path string, checks ...HealthChecker) {
197: 	InstallPathHandlerWithHealthyFunc(mux, path, nil, checks...)
198: }
199: 
200: // InstallPathHandlerWithHealthyFunc is like InstallPathHandler, but calls firstTimeHealthy exactly once
201: // when the handler succeeds for the first time.
202: func InstallPathHandlerWithHealthyFunc(mux mux, path string, firstTimeHealthy func(), checks ...HealthChecker) {
203: 	if len(checks) == 0 {
204: 		klog.V(5).Info("No default health checks specified. Installing the ping handler.")
205: 		checks = []HealthChecker{PingHealthz}
206: 	}
207: 
208: 	klog.V(5).Infof("Installing health checkers for (%v): %v", path, formatQuoted(checkerNames(checks...)...))
209: 
210: 	name := strings.Split(strings.TrimPrefix(path, "/"), "/")[0]
211: 	mux.Handle(path,
212: 		metrics.InstrumentHandlerFunc("GET",
213: 			/* group = */ "",
214: 			/* version = */ "",
215: 			/* resource = */ "",
216: 			/* subresource = */ path,
217: 			/* scope = */ "",
218: 			/* component = */ "",
219: 			/* deprecated */ false,
220: 			/* removedRelease */ "",
221: 			handleRootHealth(name, firstTimeHealthy, checks...)))
222: 	for _, check := range checks {
223: 		mux.Handle(fmt.Sprintf("%s/%v", path, check.Name()), adaptCheckToHandler(check.Check))
224: 	}
225: }
