354: func (s *EtcdOptions) addEtcdHealthEndpoint(c *server.Config) error {
355: 	healthCheck, err := storagefactory.CreateHealthCheck(s.StorageConfig, c.DrainedNotify())
356: 	if err != nil {
357: 		return err
358: 	}
359: 	c.AddHealthChecks(healthz.NamedGroupedCheck("etcd", "etcd", func(r *http.Request) error {
360: 		return healthCheck()
361: 	}))
362: 
363: 	readyCheck, err := storagefactory.CreateReadyCheck(s.StorageConfig, c.DrainedNotify())
364: 	if err != nil {
365: 		return err
366: 	}
367: 	c.AddReadyzChecks(healthz.NamedGroupedCheck("etcd-readiness", "etcd-readiness", func(r *http.Request) error {
368: 		return readyCheck()
369: 	}))
370: 
371: 	if len(s.EtcdServersOverrides) != 0 {
372: 		// multi overrides servers may in different order
373: 		// example: ["apps/deployments#s2.example.com;s1.example.com","apps/replicasets#s1.example.com;s2.example.com"]
374: 		overrides, err := ParseEtcdServersOverrides(s.EtcdServersOverrides)
375: 		if err != nil {
376: 			return err
377: 		}
378: 		// multi overrides may point to the same servers
379: 		// example: ["apps/deployments#s1.example.com;s2.example.com","apps/replicasets#s1.example.com;s2.example.com"]
380: 		serversSets := sets.NewString()
381: 		for _, override := range overrides {
382: 			sortedServers := make([]string, len(override.Servers))
383: 			// use a copied slice to avoid modifying the original slice for client in SetEtcdLocation
384: 			copy(sortedServers, override.Servers)
385: 			sort.Strings(sortedServers)
386: 			serversKeyStr := strings.Join(sortedServers, ";")
387: 			if serversSets.Has(serversKeyStr) {
388: 				continue
389: 			}
390: 			serversSets.Insert(serversKeyStr)
391: 
392: 			sc := s.StorageConfig
393: 			sc.Transport.ServerList = override.Servers
394: 
395: 			healthCheck, err := storagefactory.CreateHealthCheck(sc, c.DrainedNotify())
396: 			if err != nil {
397: 				return err
398: 			}
399: 			c.AddHealthChecks(healthz.NamedGroupedCheck(fmt.Sprintf("etcd-override-%d", len(serversSets)-1), "etcd", func(r *http.Request) error {
400: 				return healthCheck()
401: 			}))
402: 
403: 			readyCheck, err := storagefactory.CreateReadyCheck(sc, c.DrainedNotify())
404: 			if err != nil {
405: 				return err
406: 			}
407: 			c.AddReadyzChecks(healthz.NamedGroupedCheck(fmt.Sprintf("etcd-override-readiness-%d", len(serversSets)-1), "etcd-readiness", func(r *http.Request) error {
408: 				return readyCheck()
409: 			}))
410: 		}
411: 	}
412: 	return nil
413: }
