142: // delayedHealthCheck wraps a health check which will not fail until the explicitly defined delay has elapsed. This
143: // is intended for use primarily for livez health checks.
144: func delayedHealthCheck(check healthz.HealthChecker, clock clock.Clock, delay time.Duration) healthz.HealthChecker {
145: 	return delayedLivezCheck{
146: 		check,
147: 		clock.Now().Add(delay),
148: 		clock,
149: 	}
150: }
151: 
152: type delayedLivezCheck struct {
153: 	check      healthz.HealthChecker
154: 	startCheck time.Time
155: 	clock      clock.Clock
156: }
157: 
158: func (c delayedLivezCheck) Name() string {
159: 	return c.check.Name()
160: }
161: 
162: func (c delayedLivezCheck) Check(req *http.Request) error {
163: 	if c.clock.Now().After(c.startCheck) {
164: 		return c.check.Check(req)
165: 	}
166: 	return nil
167: }
